import{_ as o,o as t,c as a,ah as i}from"./chunks/framework.Bi9enVNS.js";const u=JSON.parse('{"title":"Concepts","description":"","frontmatter":{},"headers":[],"relativePath":"en/guide/concepts.md","filePath":"en/guide/concepts.md","lastUpdated":1774205896000}'),n={name:"en/guide/concepts.md"};function s(r,e,c,l,d,p){return t(),a("div",null,[...e[0]||(e[0]=[i('<h1 id="concepts" tabindex="-1">Concepts <a class="header-anchor" href="#concepts" aria-label="Permalink to &quot;Concepts&quot;">​</a></h1><p>These concepts make the protocol and UI much easier to reason about.</p><h2 id="project" tabindex="-1">project <a class="header-anchor" href="#project" aria-label="Permalink to &quot;project&quot;">​</a></h2><p><code>project</code> is a batch-level field that identifies the logical project. It is also part of authorization and idempotency.</p><h2 id="environment" tabindex="-1">environment <a class="header-anchor" href="#environment" aria-label="Permalink to &quot;environment&quot;">​</a></h2><p><code>environment</code> is another batch-level field used for values such as <code>dev</code>, <code>staging</code>, or <code>prod</code>.</p><h2 id="source" tabindex="-1">source <a class="header-anchor" href="#source" aria-label="Permalink to &quot;source&quot;">​</a></h2><p>VLT models log origin with <code>SourceRef</code>. A valid source must resolve to:</p><ul><li><code>source_name</code></li><li><code>source_type</code></li></ul><p>It can also include:</p><ul><li><code>source_id</code></li><li><code>namespace</code></li><li><code>instance_id</code></li><li><code>labels</code></li></ul><h2 id="trace-and-span" tabindex="-1">trace and span <a class="header-anchor" href="#trace-and-span" aria-label="Permalink to &quot;trace and span&quot;">​</a></h2><ul><li><code>trace_id</code> identifies the whole flow</li><li><code>span_id</code> identifies a local step</li><li><code>trace_flags</code> stores trace-level flags</li></ul><p>The current implementation validates these fields but does not derive topology from span parent-child relationships.</p><h2 id="source-fingerprint" tabindex="-1">source_fingerprint <a class="header-anchor" href="#source-fingerprint" aria-label="Permalink to &quot;source_fingerprint&quot;">​</a></h2><p>This is one of the most important concepts in the implementation. It is derived from:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>project + environment + source_type + source_name + instance_id</span></span></code></pre></div><p>It is used as:</p><ul><li>the lane identifier in timeline</li><li>the node identifier in topology</li><li>the aggregation key for source-instance views</li></ul><h2 id="timeline-lane" tabindex="-1">timeline lane <a class="header-anchor" href="#timeline-lane" aria-label="Permalink to &quot;timeline lane&quot;">​</a></h2><p>Each timeline lane maps to one <code>source_fingerprint</code>. In other words, lanes are instance-level views, not abstract service-level views.</p><h2 id="topology-edge" tabindex="-1">topology edge <a class="header-anchor" href="#topology-edge" aria-label="Permalink to &quot;topology edge&quot;">​</a></h2><p>Topology edges come from adjacent source segments inside the same trace. That means:</p><ul><li>they reflect observed time flow through sources</li><li>they are not a span DAG</li><li>consecutive identical sources are collapsed first</li></ul><h2 id="source-tree" tabindex="-1">source tree <a class="header-anchor" href="#source-tree" aria-label="Permalink to &quot;source tree&quot;">​</a></h2><p><code>GET /v1/sources</code> returns:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>source_type -&gt; source_name -&gt; instance_id</span></span></code></pre></div><p>It answers “which source instances are present?”, not “how did one trace travel?”.</p><h2 id="sources-of-truth" tabindex="-1">Sources of truth <a class="header-anchor" href="#sources-of-truth" aria-label="Permalink to &quot;Sources of truth&quot;">​</a></h2><ul><li><code>proto/vlt/common/v1/common.proto</code></li><li><code>proto/vlt/logs/v1/logs.proto</code></li><li><code>internal/ingest/normalize.go</code></li><li><code>internal/store/store.go</code></li><li><code>internal/store/memory/memory.go</code></li></ul>',30)])])}const m=o(n,[["render",s]]);export{u as __pageData,m as default};
